/**
 * Get statistics about past paper questions for a specific subject and year
 * @param subject - The subject name (e.g., "Mathematics")
 * @param year - The year (number or string)
 * @returns Object with count and topics array, or undefined if not found
 */
export function getPastPaperStats(
  subject: string,
  year: number | string
): { count: number; topics: string[] } | undefined {
  const yearNum = typeof year === 'string' ? parseInt(year, 10) : year;
  if (isNaN(yearNum)) return undefined;

  const subjectData = pastPaperQuestionsData[subject];
  if (!subjectData) return undefined;

  let totalCount = 0;
  const topicsSet = new Set<string>();

  // Iterate through all papers for this subject
  for (const paperData of Object.values(subjectData)) {
    const yearQuestions = paperData[yearNum];
    if (yearQuestions) {
      totalCount += yearQuestions.length;
      yearQuestions.forEach(q => {
        if (q.topic) {
          topicsSet.add(q.topic);
        }
      });
    }
  }

  return totalCount > 0
    ? { count: totalCount, topics: Array.from(topicsSet).sort() }
    : undefined;
}

/**
 * Get past paper questions by metadata (subject, grade level, year, paper number)
 * @param baseSubject - The base subject name (e.g., "Mathematics")
 * @param gradeLevel - The grade level (should be 12 for past papers)
 * @param year - The year of the paper
 * @param paperNumber - The paper number (e.g., "Paper 1", "Paper 2")
 * @returns Array of PastPaperQuestion objects
 */
export function getPastPaperQuestionsByMetadata(
  baseSubject: string,
  gradeLevel: number,
  year: number,
  paperNumber: string
): PastPaperQuestion[] {
  // Only Grade 12 has past papers
  if (gradeLevel !== 12) {
    return [];
  }

  const subjectData = pastPaperQuestionsData[baseSubject];
  if (!subjectData) {
    return [];
  }

  const paperData = subjectData[paperNumber];
  if (!paperData) {
    return [];
  }

  const yearQuestions = paperData[year];
  return yearQuestions || [];
}

// Export the data for use in API routes
